1	{% extends "base.html" %}
2	{% block title %}Reports & Exports{% endblock %}
3	{% block content %}
4	<h1>Reports &amp; Exports</h1>
5	
6	<div class="card">
7	  <h3>Operations Metrics</h3>
8	  <form id="metrics-form">
9	    <div class="form-row">
10	      <div class="form-group"><label>Date Start</label><input name="date_start" type="date" required></div>
11	      <div class="form-group"><label>Date End</label><input name="date_end" type="date" required></div>
12	    </div>
13	    <button type="submit" class="btn btn-primary">Load Metrics</button>
14	  </form>
15	  <div id="metrics-display" class="mt-1"></div>
16	</div>
17	
18	<div class="card">
19	  <h3>Request Export</h3>
20	  <div id="export-result"></div>
21	  <form id="export-form">
22	    <div class="form-row">
23	      <!-- store_id is derived from the session -->
24	      <div class="form-group"><label>Export Type</label>
25	        <select name="export_type"><option>tickets</option><option>members</option><option>audit</option><option>recalls</option></select>
26	      </div>
27	    </div>
28	    <div class="form-row">
29	      <div class="form-group"><label>Watermark</label><select name="watermark_enabled"><option value="false">No</option><option value="true">Yes</option></select></div>
30	      <div class="form-group"><label>Attribution</label><input name="attribution_text" placeholder="Optional"></div>
31	    </div>
32	    <button type="submit" class="btn btn-primary">Request Export</button>
33	  </form>
34	</div>
35	
36	<div class="card">
37	  <h3>Export Approval (Supervisor)</h3>
38	  <div class="form-row">
39	    <div class="form-group"><label>Request ID</label><input id="exp-id" type="number"></div>
40	  </div>
41	  <div style="display:flex;gap:.5rem">
42	    <button class="btn btn-success btn-sm" onclick="approveExport()">Approve</button>
43	    <button class="btn btn-danger btn-sm" onclick="rejectExport()">Reject</button>
44	    <button class="btn btn-primary btn-sm" onclick="executeExport()">Execute</button>
45	  </div>
46	  <div class="form-group mt-1"><label>Reason (for rejection)</label><input id="exp-reason"></div>
47	  <div id="approval-result" class="mt-1"></div>
48	</div>
49	
50	<script>
51	const api=(u,b,m='POST')=>fetch(u,{method:m,headers:{'Content-Type':'application/json'},...(m==='GET'?{}:{body:JSON.stringify(b)})}).then(r=>r.json());
52	const showR=(el,d)=>{el.innerHTML=d.error?'<div class="msg msg-error">'+H(d.error.message)+'</div>':'<div class="msg msg-success">'+H(JSON.stringify(d.data,null,1))+'</div>';};
53	
54	document.getElementById('metrics-form').addEventListener('submit',async e=>{
55	  e.preventDefault();const fd=new FormData(e.target);
56	  const r=await api('/api/exports/metrics?date_start='+encodeURIComponent(fd.get('date_start'))+'&date_end='+encodeURIComponent(fd.get('date_end')),null,'GET');
57	  const el=document.getElementById('metrics-display');
58	  if(r.error){el.innerHTML='<div class="msg msg-error">'+H(r.error.message)+'</div>';return;}
59	  const m=r.data;
60	  el.innerHTML='<div class="metrics-grid">'
61	    +'<div class="metric-card"><div class="value">'+H(m.order_volume)+'</div><div class="label">Order Volume</div></div>'
62	    +'<div class="metric-card"><div class="value">$'+H(m.revenue.toFixed(2))+'</div><div class="label">Revenue</div></div>'
63	    +'<div class="metric-card"><div class="value">'+H(m.refund_rate.toFixed(1))+'%</div><div class="label">Refund Rate</div></div>'
64	    +'<div class="metric-card"><div class="value">'+H(m.load_factor.toFixed(1))+'%</div><div class="label">Load Factor</div></div>'
65	    +'</div>';
66	});
67	
68	document.getElementById('export-form').addEventListener('submit',async e=>{
69	  e.preventDefault();const fd=new FormData(e.target),b={};
70	  fd.forEach((v,k)=>b[k]=k==='store_id'?+v:k==='watermark_enabled'?v==='true':v);
71	  showR(document.getElementById('export-result'),await api('/api/exports/requests',b));
72	});
73	
74	const eid=()=>document.getElementById('exp-id').value;
75	const apRes=()=>document.getElementById('approval-result');
76	const exportSummary=d=>'Export #'+H(d.id)+' — <span class="badge badge-'+H(d.status)+'">'+H(d.status)+'</span>';
77	
78	async function approveExport(){
79	  if (!eid()) { showMsg(apRes(),'error','Enter an export request ID.'); return; }
80	  const password=window.prompt('Re-enter your password to approve export request #'+eid()+':');
81	  if(!password)return;
82	  const r=await api('/api/exports/requests/'+eid()+'/approve',{password});
83	  showApiResult(apRes(),r,exportSummary);
84	}
85	async function rejectExport(){
86	  if (!eid()) { showMsg(apRes(),'error','Enter an export request ID.'); return; }
87	  const reason=document.getElementById('exp-reason').value.trim();
88	  if (!reason) { showMsg(apRes(),'error','Rejection reason is required.'); return; }
89	  if (!confirmAction('Reject export request #'+eid()+'?')) return;
90	  const r=await api('/api/exports/requests/'+eid()+'/reject',{reason});
91	  showApiResult(apRes(),r,exportSummary);
92	}
93	async function executeExport(){
94	  if (!eid()) { showMsg(apRes(),'error','Enter an export request ID.'); return; }
95	  if (!confirmAction('Execute export request #'+eid()+'? This is one-time only.')) return;
96	  const r=await api('/api/exports/requests/'+eid()+'/execute',{});
97	  showApiResult(apRes(),r,d=>exportSummary(d)+'<br>Completed at: '+H(d.completed_at||'—'));
98	}
99	</script>
100	{% endblock %}
101

1	{% extends "base.html" %}
2	{% block title %}Notifications{% endblock %}
3	{% block content %}
4	<h1>Notification Center</h1>
5	
6	<div class="card">
7	  <h3>Log Message / Call Attempt</h3>
8	  <div id="msg-result"></div>
9	  <form id="msg-form">
10	    <div class="form-row">
11	      <div class="form-group"><label>Ticket ID</label><input name="ticket_id" type="number" required></div>
12	      <div class="form-group"><label>Channel</label>
13	        <select name="contact_channel"><option value="logged_message">Logged Message</option><option value="phone_call">Phone Call</option></select>
14	      </div>
15	    </div>
16	    <div class="form-group"><label>Message Body</label><textarea name="message_body" required></textarea></div>
17	    <div class="form-row">
18	      <div class="form-group"><label>Call Status (if phone)</label>
19	        <select name="call_attempt_status"><option value="">N/A</option><option value="succeeded">Succeeded</option><option value="failed">Failed</option><option value="voicemail">Voicemail</option><option value="no_answer">No Answer</option></select>
20	      </div>
21	      <div class="form-group"><label>Retry in (minutes)</label><input name="retry_minutes" type="number"></div>
22	    </div>
23	    <button type="submit" class="btn btn-primary">Log</button>
24	  </form>
25	</div>
26	
27	<div class="card">
28	  <h3>Send from Template</h3>
29	  <form id="tpl-form">
30	    <div class="form-row">
31	      <div class="form-group"><label>Ticket ID</label><input name="ticket_id" type="number" required></div>
32	      <div class="form-group"><label>Template Code</label>
33	        <select name="template_code"><option>accepted</option><option>rescheduled</option><option>arrived</option><option>completed</option><option>refunded</option></select>
34	      </div>
35	      <!-- store_id is derived from the session -->
36	    </div>
37	    <div class="form-group"><label>Context JSON</label><input name="context" value='{"customer_name":"Customer"}' style="font-family:monospace"></div>
38	    <button type="submit" class="btn btn-primary">Send Template</button>
39	  </form>
40	  <div id="tpl-result" class="mt-1"></div>
41	</div>
42	
43	<div class="card">
44	  <h3>Message History</h3>
45	  <div class="form-row">
46	    <div class="form-group"><label>Ticket ID</label><input id="hist-ticket" type="number"></div>
47	    <div class="form-group" style="padding-top:1.2rem"><button class="btn btn-primary btn-sm" onclick="loadHistory()">Load</button></div>
48	  </div>
49	  <div id="history-list"></div>
50	</div>
51	
52	<div class="card">
53	  <h3>Pending Retries</h3>
54	  <button class="btn btn-warn btn-sm" onclick="loadRetries()">Load Pending</button>
55	  <div id="retry-list" class="mt-1"></div>
56	</div>
57	
58	<script>
59	const api=(u,b,m='POST')=>fetch(u,{method:m,headers:{'Content-Type':'application/json'},...(m==='GET'?{}:{body:JSON.stringify(b)})}).then(r=>r.json());
60	const showR=(el,d)=>{el.innerHTML=d.error?'<div class="msg msg-error">'+H(d.error.message)+'</div>':'<div class="msg msg-success">Logged #'+H(d.data?.id||'OK')+'</div>';};
61	
62	document.getElementById('msg-form').addEventListener('submit',async e=>{
63	  e.preventDefault();const fd=new FormData(e.target),b={};
64	  fd.forEach((v,k)=>{if(!v)return;b[k]=['ticket_id','retry_minutes'].includes(k)?+v:v;});
65	  showR(document.getElementById('msg-result'),await api('/api/notifications/messages',b));
66	});
67	
68	document.getElementById('tpl-form').addEventListener('submit',async e=>{
69	  e.preventDefault();const fd=new FormData(e.target);
70	  const b={ticket_id:+fd.get('ticket_id'),template_code:fd.get('template_code'),store_id:+fd.get('store_id'),context:JSON.parse(fd.get('context'))};
71	  showR(document.getElementById('tpl-result'),await api('/api/notifications/messages/template',b));
72	});
73	
74	async function loadHistory(){
75	  const r=await api('/api/notifications/tickets/'+document.getElementById('hist-ticket').value+'/messages',null,'GET');
76	  const el=document.getElementById('history-list');
77	  if(r.error){el.innerHTML='<div class="msg msg-error">'+H(r.error.message)+'</div>';return;}
78	  if(!r.data?.length){el.innerHTML='<div class="msg msg-info">No messages</div>';return;}
79	  el.innerHTML='<table><tr><th>ID</th><th>Channel</th><th>Body</th><th>Call Status</th><th>Retry At</th><th>Time</th></tr>'
80	    +r.data.map(m=>'<tr><td>'+H(m.id)+'</td><td>'+H(m.contact_channel)+'</td><td>'+H(m.message_body)+'</td><td>'+H(m.call_attempt_status||'—')+'</td><td>'+H(m.retry_at||'—')+'</td><td class="text-sm text-muted">'+H(m.created_at)+'</td></tr>').join('')+'</table>';
81	}
82	async function loadRetries(){
83	  const r=await api('/api/notifications/retries/pending',null,'GET');
84	  const el=document.getElementById('retry-list');
85	  if(r.error){el.innerHTML='<div class="msg msg-error">'+H(r.error.message)+'</div>';return;}
86	  if(!r.data?.length){el.innerHTML='<div class="msg msg-info">No pending retries</div>';return;}
87	  el.innerHTML='<table><tr><th>ID</th><th>Ticket</th><th>Retry At</th></tr>'
88	    +r.data.map(m=>'<tr><td>'+H(m.id)+'</td><td>'+H(m.ticket_id)+'</td><td>'+H(m.retry_at)+'</td></tr>').join('')+'</table>';
89	}
90	</script>
91	{% endblock %}
