1	{% extends "base.html" %}
2	{% block title %}Tickets{% endblock %}
3	{% block content %}
4	<h1>Buyback Tickets</h1>
5	
6	<div class="card">
7	  <h3>Create New Ticket</h3>
8	  <div id="ticket-result"></div>
9	  <form id="ticket-form">
10	    <div class="form-row">
11	      <div class="form-group"><label>Customer Name</label><input name="customer_name" required></div>
12	      <div class="form-group"><label>Phone (last 4)</label><input name="customer_phone_last4" maxlength="4"></div>
13	    </div>
14	    <div class="form-row">
15	      <div class="form-group"><label>Category</label>
16	        <select name="clothing_category" required>
17	          <option value="">Select...</option><option>shirts</option><option>pants</option><option>jackets</option><option>dresses</option><option>mixed</option>
18	        </select>
19	      </div>
20	      <div class="form-group"><label>Condition Grade</label>
21	        <select name="condition_grade" required>
22	          <option value="">Select...</option><option value="A">A — Excellent</option><option value="B">B — Good</option><option value="C">C — Fair</option>
23	        </select>
24	      </div>
25	    </div>
26	    <div class="form-row">
27	      <div class="form-group"><label>Estimated Weight (lbs)</label><input name="estimated_weight_lbs" type="number" step="0.1" min="0.1" required></div>
28	      <div class="form-group"><label>Phone Preference</label>
29	        <select name="customer_phone_preference"><option value="standard_calls">Standard</option><option value="calls_only">Calls Only</option></select>
30	      </div>
31	    </div>
32	    <!-- store_id is derived from the session — never set client-side -->
33	    <button type="submit" class="btn btn-primary">Create Ticket &amp; Calculate Payout</button>
34	  </form>
35	</div>
36	
37	<div class="card">
38	  <h3>Ticket Actions</h3>
39	  <div class="form-row">
40	    <div class="form-group"><label>Ticket ID</label><input id="action-ticket-id" type="number" placeholder="Enter ticket ID"></div>
41	  </div>
42	  <div style="display:flex;gap:.5rem;flex-wrap:wrap">
43	    <button class="btn btn-primary btn-sm" onclick="ticketAction('submit-qc')">Submit for QC</button>
44	    <button class="btn btn-warn btn-sm" onclick="showVarianceConfirm()">Confirm Variance</button>
45	    <button class="btn btn-danger btn-sm" onclick="showRefundForm()">Initiate Refund</button>
46	    <button class="btn btn-sm" style="background:#6b7280;color:#fff" onclick="showCancelForm()">Cancel</button>
47	  </div>
48	  <div id="action-result" class="mt-1"></div>
49	
50	  <!-- Variance confirmation (hidden until needed) -->
51	  <div id="variance-form" class="hidden mt-2 card">
52	    <h3>Confirm Variance</h3>
53	    <div class="form-group"><label>Confirmation Note</label><textarea id="variance-note" required></textarea></div>
54	    <button class="btn btn-warn" onclick="confirmVariance()">Confirm</button>
55	  </div>
56	
57	  <!-- Variance approval -->
58	  <div id="variance-approval" class="hidden mt-2 card">
59	    <h3>Supervisor Variance Approval</h3>
60	    <div class="form-group"><label>Approval Request ID</label><input id="var-req-id" type="number"></div>
61	    <div style="display:flex;gap:.5rem">
62	      <button class="btn btn-success" onclick="approveVariance()">Approve (Password Confirmed)</button>
63	      <button class="btn btn-danger" onclick="rejectVariance()">Reject</button>
64	    </div>
65	    <div class="form-group mt-1"><label>Reason (for rejection)</label><input id="var-reject-reason"></div>
66	  </div>
67	
68	  <!-- Refund form -->
69	  <div id="refund-form" class="hidden mt-2 card">
70	    <h3>Initiate Refund</h3>
71	    <div class="form-row">
72	      <div class="form-group"><label>Amount (blank = full)</label><input id="refund-amount" type="number" step="0.01"></div>
73	      <div class="form-group"><label>Reason</label><input id="refund-reason"></div>
74	    </div>
75	    <button class="btn btn-danger" onclick="initiateRefund()">Submit Refund Request</button>
76	  </div>
77	
78	  <!-- Refund approval -->
79	  <div id="refund-approval" class="mt-2 card">
80	    <h3>Refund Approval (Supervisor)</h3>
81	    <div class="form-group"><label>Ticket ID</label><input id="refund-approve-id" type="number"></div>
82	    <div style="display:flex;gap:.5rem">
83	      <button class="btn btn-success" onclick="approveRefund()">Approve Refund</button>
84	      <button class="btn btn-danger" onclick="rejectRefund()">Reject Refund</button>
85	    </div>
86	    <div class="form-group mt-1"><label>Reason (for rejection)</label><input id="refund-reject-reason"></div>
87	  </div>
88	
89	  <!-- Cancel form -->
90	  <div id="cancel-form" class="hidden mt-2 card">
91	    <h3>Cancel Ticket</h3>
92	    <div class="form-group"><label>Reason</label><input id="cancel-reason" required></div>
93	    <button class="btn btn-danger" onclick="cancelTicket()">Cancel Ticket</button>
94	  </div>
95	</div>
96	
97	<script>
98	const api = (url, body) => fetch(url, {method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(body)}).then(r=>r.json());
99	const show = (id) => document.getElementById(id).classList.remove('hidden');
100	const tid = () => parseInt(document.getElementById('action-ticket-id').value);
101	const actionResult = () => document.getElementById('action-result');
102	
103	function requireTicketId() {
104	  const v = tid();
105	  if (!Number.isFinite(v) || v <= 0) {
106	    showMsg(actionResult(), 'error', 'Enter a ticket ID first.');
107	    return null;
108	  }
109	  return v;
110	}
111	
112	// Format a ticket summary line for feedback messages.
113	function ticketSummary(t) {
114	  return 'Ticket #' + H(t.id) + ' — <span class="badge badge-' + H(t.status) + '">'
115	    + H(t.status) + '</span>';
116	}
117	
118	document.getElementById('ticket-form').addEventListener('submit', async (e) => {
119	  e.preventDefault();
120	  const btn = e.target.querySelector('button[type="submit"]');
121	  btn.classList.add('is-loading');
122	  try {
123	    const fd = new FormData(e.target);
124	    const body = {};
125	    fd.forEach((v,k) => body[k] = (k === 'estimated_weight_lbs' || k === 'store_id') ? Number(v) : v);
126	    const r = await api('/api/tickets', body);
127	    const el = document.getElementById('ticket-result');
128	    if (r.error) {
129	      showMsg(el, 'error', escapeHtml(r.error.message));
130	      return;
131	    }
132	    const t = r.data;
133	    el.innerHTML = '<div class="msg msg-success">'
134	      + 'Ticket #' + H(t.id) + ' created — <span class="badge badge-' + H(t.status) + '">' + H(t.status) + '</span><br>'
135	      + '<strong>Estimated Payout: $' + H((t.estimated_payout || 0).toFixed(2)) + '</strong>'
136	      + (t.estimated_cap_applied ? ' <em>(cap applied)</em>' : '')
137	      + '<br><span class="text-sm text-muted">Rate: $' + H((t.estimated_base_rate || 0).toFixed(2))
138	      + '/lb &middot; Bonus: ' + H(t.estimated_bonus_pct || 0) + '%</span>'
139	      + '</div>';
140	  } finally {
141	    btn.classList.remove('is-loading');
142	  }
143	});
144	
145	async function ticketAction(action) {
146	  if (!requireTicketId()) return;
147	  const r = await api('/api/tickets/' + tid() + '/' + action, {});
148	  showApiResult(actionResult(), r, ticketSummary);
149	}
150	
151	function showVarianceConfirm() { show('variance-form'); show('variance-approval'); }
152	function showRefundForm() { show('refund-form'); }
153	function showCancelForm() { show('cancel-form'); }
154	
155	async function confirmVariance() {
156	  if (!requireTicketId()) return;
157	  const note = document.getElementById('variance-note').value.trim();
158	  if (!note) { showMsg(actionResult(), 'error', 'Confirmation note is required.'); return; }
159	  const r = await api('/api/tickets/' + tid() + '/confirm-variance', {confirmation_note: note});
160	  showApiResult(actionResult(), r, d => 'Variance confirmed — approval request #' + d.id);
161	  if (r.data) document.getElementById('var-req-id').value = r.data.id;
162	}
163	
164	async function approveVariance() {
165	  const rid = document.getElementById('var-req-id').value;
166	  if (!rid) { showMsg(actionResult(), 'error', 'Enter an approval request ID.'); return; }
167	  const password = window.prompt('Re-enter your password to approve this variance:');
168	  if (!password) return;
169	  const r = await api('/api/tickets/variance/' + rid + '/approve', {password});
170	  showApiResult(actionResult(), r, ticketSummary);
171	}
172	
173	async function rejectVariance() {
174	  const rid = document.getElementById('var-req-id').value;
175	  if (!rid) { showMsg(actionResult(), 'error', 'Enter an approval request ID.'); return; }
176	  const reason = document.getElementById('var-reject-reason').value.trim();
177	  if (!reason) { showMsg(actionResult(), 'error', 'Rejection reason is required.'); return; }
178	  if (!confirmAction('Reject this variance approval? This cannot be undone.')) return;
179	  const r = await api('/api/tickets/variance/' + rid + '/reject', {reason});
180	  showApiResult(actionResult(), r, d => 'Variance rejected — request #' + d.id);
181	}
182	
183	async function initiateRefund() {
184	  if (!requireTicketId()) return;
185	  const body = {};
186	  const amt = document.getElementById('refund-amount').value;
187	  if (amt) {
188	    const reason = document.getElementById('refund-reason').value.trim();
189	    if (!reason) { showMsg(actionResult(), 'error', 'Reason required for partial refund.'); return; }
190	    body.refund_amount = parseFloat(amt);
191	    body.reason = reason;
192	  }
193	  if (!confirmAction('Submit a refund request for ticket #' + tid() + '?')) return;
194	  const r = await api('/api/tickets/' + tid() + '/refund', body);
195	  showApiResult(actionResult(), r, ticketSummary);
196	}
197	
198	async function approveRefund() {
199	  const id = document.getElementById('refund-approve-id').value;
200	  if (!id) { showMsg(actionResult(), 'error', 'Enter a ticket ID.'); return; }
201	  const password = window.prompt('Re-enter your password to approve refund for ticket #' + id + ':');
202	  if (!password) return;
203	  const r = await api('/api/tickets/' + id + '/refund/approve', {password});
204	  showApiResult(actionResult(), r, ticketSummary);
205	}
206	
207	async function rejectRefund() {
208	  const id = document.getElementById('refund-approve-id').value;
209	  if (!id) { showMsg(actionResult(), 'error', 'Enter a ticket ID.'); return; }
210	  const reason = document.getElementById('refund-reject-reason').value.trim();
211	  if (!reason) { showMsg(actionResult(), 'error', 'Rejection reason is required.'); return; }
212	  if (!confirmAction('Reject refund for ticket #' + id + '?')) return;
213	  const r = await api('/api/tickets/' + id + '/refund/reject', {reason});
214	  showApiResult(actionResult(), r, ticketSummary);
215	}
216	
217	async function cancelTicket() {
218	  if (!requireTicketId()) return;
219	  const reason = document.getElementById('cancel-reason').value.trim();
220	  if (!reason) { showMsg(actionResult(), 'error', 'Cancellation reason is required.'); return; }
221	  if (!confirmAction('Cancel ticket #' + tid() + '? This cannot be undone.')) return;
222	  const r = await api('/api/tickets/' + tid() + '/cancel', {reason});
223	  showApiResult(actionResult(), r, ticketSummary);
224	}
225	</script>
226	{% endblock %}
