2	<html lang="en">
3	<head>
4	  <meta charset="UTF-8">
5	  <meta name="viewport" content="width=device-width, initial-scale=1.0">
6	  <title>ReclaimOps — {% block title %}Dashboard{% endblock %}</title>
7	  <link rel="stylesheet" href="/static/css/style.css">
8	  <!-- HTMX is vendored locally — no network access at runtime -->
9	  <script src="/static/js/htmx.min.js"></script>
10	  <script>
11	    // Read csrf_token cookie and attach X-CSRF-Token to every fetch + HTMX request.
12	    function getCsrfToken() {
13	      const c = document.cookie.split('; ').find(x => x.startsWith('csrf_token='));
14	      return c ? decodeURIComponent(c.split('=')[1]) : '';
15	    }
16	    (function() {
17	      const orig = window.fetch;
18	      window.fetch = function(url, opts) {
19	        opts = opts || {};
20	        opts.headers = opts.headers || {};
21	        const token = getCsrfToken();
22	        if (token) opts.headers['X-CSRF-Token'] = token;
23	        return orig.call(window, url, opts);
24	      };
25	    })();
26	
27	    // ── Shared UI helpers ──
28	
29	    // Render a success/error/info message into an element.
30	    function showMsg(elOrId, type, text) {
31	      const el = typeof elOrId === 'string' ? document.getElementById(elOrId) : elOrId;
32	      if (!el) return;
33	      el.innerHTML = '<div class="msg msg-' + type + '">' + text + '</div>';
34	    }
35	
36	    // Render an API response — picks success/error automatically.
37	    // Optional formatter builds a custom success message; default shows a generic line.
38	    function showApiResult(elOrId, resp, successFormatter) {
39	      const el = typeof elOrId === 'string' ? document.getElementById(elOrId) : elOrId;
40	      if (!el) return;
41	      if (resp && resp.error) {
42	        showMsg(el, 'error', escapeHtml(resp.error.message || 'Request failed'));
43	        return;
44	      }
45	      const body = successFormatter ? successFormatter(resp.data) : 'Success.';
46	      showMsg(el, 'success', body);
47	    }
48	
49	    // Minimal HTML escape for user-facing text.
50	    function escapeHtml(s) {
51	      if (s == null) return '';
52	      return String(s).replace(/[&<>"']/g, c =>
53	        ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
54	    }
55	    // Shorter alias used across templates: H(value) MUST wrap every
56	    // dynamic value before it is concatenated into an innerHTML
57	    // assignment. The browser treats the result as parsed HTML, so
58	    // unescaped user input would otherwise execute scripts.
59	    const H = escapeHtml;
60	
61	    // Disable a form's submit button while an async handler runs.
62	    async function withSubmitLock(formOrBtn, handler) {
63	      const btn = formOrBtn.tagName === 'BUTTON'
64	        ? formOrBtn
65	        : formOrBtn.querySelector('button[type="submit"], button:not([type])');
66	      try {
67	        if (btn) btn.classList.add('is-loading');
68	        return await handler();
69	      } finally {
70	        if (btn) btn.classList.remove('is-loading');
71	      }
72	    }
73	
74	    // Confirm destructive actions with a standard prompt. Returns boolean.
75	    function confirmAction(message) {
76	      return window.confirm(message);
77	    }
78	  </script>
79	</head>
80	<body hx-headers='js:{"X-CSRF-Token": getCsrfToken()}'>
81	  <div class="app-shell">
82	    <nav class="sidebar">
83	      <h2>ReclaimOps</h2>
84	      <a href="/ui/tickets">Tickets</a>
85	      <a href="/ui/qc">QC &amp; Traceability</a>
86	      <a href="/ui/tables">Tables / Rooms</a>
87	      <a href="/ui/notifications">Notifications</a>
88	      <a href="/ui/members">Members</a>
89	      <a href="/ui/exports">Reports &amp; Exports</a>
90	      <a href="/ui/schedules">Schedules</a>
91	      <a href="#" hx-post="/api/auth/logout" hx-swap="none"
92	         onclick="setTimeout(()=>location.href='/ui/login',300)"
93	         style="margin-top:2rem;color:#f87171">Logout</a>
94	    </nav>
95	    <main class="main-content">
96	      {% block content %}{% endblock %}
97	    </main>
98	  </div>
99	</body>
