1	{% extends "base.html" %}
2	{% block title %}Tickets{% endblock %}
3	{% block content %}
4	<h1>Buyback Tickets</h1>
5	
6	<div class="card">
7	  <h3>Create New Ticket</h3>
8	  <div id="ticket-result"></div>
9	  <form id="ticket-form" hx-target="#ticket-result">
10	    <div class="form-row">
11	      <div class="form-group"><label>Customer Name</label><input name="customer_name" required></div>
12	      <div class="form-group"><label>Phone (last 4)</label><input name="customer_phone_last4" maxlength="4"></div>
13	    </div>
14	    <div class="form-row">
15	      <div class="form-group"><label>Category</label>
16	        <select name="clothing_category" required>
17	          <option value="">Select...</option><option>shirts</option><option>pants</option><option>jackets</option><option>dresses</option><option>mixed</option>
18	        </select>
19	      </div>
20	      <div class="form-group"><label>Condition Grade</label>
21	        <select name="condition_grade" required>
22	          <option value="">Select...</option><option value="A">A — Excellent</option><option value="B">B — Good</option><option value="C">C — Fair</option>
23	        </select>
24	      </div>
25	    </div>
26	    <div class="form-row">
27	      <div class="form-group"><label>Estimated Weight (lbs)</label><input name="estimated_weight_lbs" type="number" step="0.1" min="0.1" required></div>
28	      <div class="form-group"><label>Phone Preference</label>
29	        <select name="customer_phone_preference"><option value="standard_calls">Standard</option><option value="calls_only">Calls Only</option></select>
30	      </div>
31	    </div>
32	    <!-- store_id is derived from the session — never set client-side -->
33	    <button type="submit" class="btn btn-primary">Create Ticket &amp; Calculate Payout</button>
34	  </form>
35	</div>
36	
37	<div class="card">
38	  <h3>Ticket Actions</h3>
39	  <div class="form-row">
40	    <div class="form-group"><label>Ticket ID</label><input id="action-ticket-id" type="number" placeholder="Enter ticket ID"></div>
41	  </div>
42	  <div style="display:flex;gap:.5rem;flex-wrap:wrap">
43	    <button class="btn btn-primary btn-sm" onclick="ticketAction('submit-qc')">Submit for QC</button>
44	    <button class="btn btn-warn btn-sm" onclick="showVarianceConfirm()">Confirm Variance</button>
45	    <button class="btn btn-danger btn-sm" onclick="showRefundForm()">Initiate Refund</button>
46	    <button class="btn btn-sm" style="background:#16a34a;color:#fff" onclick="dialCustomer()">Dial Customer</button>
47	    <button class="btn btn-sm" style="background:#6b7280;color:#fff" onclick="showCancelForm()">Cancel</button>
48	  </div>
49	  <div id="action-result" class="mt-1"></div>
50	
51	  <!-- Variance confirmation (hidden until needed) -->
52	  <div id="variance-form" class="hidden mt-2 card">
53	    <h3>Confirm Variance</h3>
54	    <div class="form-group"><label>Confirmation Note</label><textarea id="variance-note" required></textarea></div>
55	    <button class="btn btn-warn" onclick="confirmVariance()">Confirm</button>
56	  </div>
57	
58	  <!-- Variance approval -->
59	  <div id="variance-approval" class="hidden mt-2 card">
60	    <h3>Supervisor Variance Approval</h3>
61	    <div class="form-group"><label>Approval Request ID</label><input id="var-req-id" type="number"></div>
62	    <div style="display:flex;gap:.5rem">
63	      <button class="btn btn-success" onclick="approveVariance()">Approve (Password Confirmed)</button>
64	      <button class="btn btn-danger" onclick="rejectVariance()">Reject</button>
65	    </div>
66	    <div class="form-group mt-1"><label>Reason (for rejection)</label><input id="var-reject-reason"></div>
67	  </div>
68	
69	  <!-- Refund form -->
70	  <div id="refund-form" class="hidden mt-2 card">
71	    <h3>Initiate Refund</h3>
72	    <div class="form-row">
73	      <div class="form-group"><label>Amount (blank = full)</label><input id="refund-amount" type="number" step="0.01"></div>
74	      <div class="form-group"><label>Reason</label><input id="refund-reason"></div>
75	    </div>
76	    <button class="btn btn-danger" onclick="initiateRefund()">Submit Refund Request</button>
77	  </div>
78	
79	  <!-- Refund approval -->
80	  <div id="refund-approval" class="mt-2 card">
81	    <h3>Refund Approval (Supervisor)</h3>
82	    <div class="form-group"><label>Ticket ID</label><input id="refund-approve-id" type="number"></div>
83	    <div style="display:flex;gap:.5rem">
84	      <button class="btn btn-success" onclick="approveRefund()">Approve Refund</button>
85	      <button class="btn btn-danger" onclick="rejectRefund()">Reject Refund</button>
86	    </div>
87	    <div class="form-group mt-1"><label>Reason (for rejection)</label><input id="refund-reject-reason"></div>
88	  </div>
89	
90	  <!-- Cancel form -->
91	  <div id="cancel-form" class="hidden mt-2 card">
92	    <h3>Cancel Ticket</h3>
93	    <div class="form-group"><label>Reason</label><input id="cancel-reason" required></div>
94	    <button class="btn btn-danger" onclick="cancelTicket()">Cancel Ticket</button>
95	  </div>
96	</div>
97	
98	<script>
99	const api = (url, body) => fetch(url, {method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(body)}).then(r=>r.json());
100	const show = (id) => document.getElementById(id).classList.remove('hidden');
101	const tid = () => parseInt(document.getElementById('action-ticket-id').value);
102	const actionResult = () => document.getElementById('action-result');
103	
104	function requireTicketId() {
