1	{% extends "base.html" %}
2	{% block title %}Reports & Exports{% endblock %}
3	{% block content %}
4	<h1>Reports &amp; Exports</h1>
5	
6	<div class="card">
7	  <h3>Operations Metrics</h3>
8	  <form id="metrics-form" hx-target="#metrics-display">
9	    <div class="form-row">
10	      <div class="form-group"><label>Date Start</label><input name="date_start" type="date" required></div>
11	      <div class="form-group"><label>Date End</label><input name="date_end" type="date" required></div>
12	      <div class="form-group"><label>Category Filter</label>
13	        <select name="clothing_category"><option value="">All</option><option>shirts</option><option>pants</option><option>jackets</option><option>dresses</option><option>mixed</option></select>
14	      </div>
15	    </div>
16	    <button type="submit" class="btn btn-primary">Load Metrics</button>
17	  </form>
18	  <div id="metrics-display" class="mt-1"></div>
19	</div>
20	
21	<div class="card">
22	  <h3>Request Export</h3>
23	  <div id="export-result"></div>
24	  <form id="export-form">
25	    <div class="form-row">
26	      <!-- store_id is derived from the session -->
27	      <div class="form-group"><label>Export Type</label>
28	        <select name="export_type"><option>tickets</option><option>metrics</option></select>
29	      </div>
30	    </div>
31	    <div class="form-row">
32	      <div class="form-group"><label>Watermark</label><select name="watermark_enabled"><option value="false">No</option><option value="true">Yes</option></select></div>
33	      <div class="form-group"><label>Attribution</label><input name="attribution_text" placeholder="Optional"></div>
34	    </div>
35	    <button type="submit" class="btn btn-primary">Request Export</button>
36	  </form>
37	</div>
38	
39	<div class="card">
40	  <h3>Export Approval (Supervisor)</h3>
41	  <div class="form-row">
42	    <div class="form-group"><label>Request ID</label><input id="exp-id" type="number"></div>
43	  </div>
44	  <div style="display:flex;gap:.5rem">
45	    <button class="btn btn-success btn-sm" onclick="approveExport()">Approve</button>
46	    <button class="btn btn-danger btn-sm" onclick="rejectExport()">Reject</button>
47	    <button class="btn btn-primary btn-sm" onclick="executeExport()">Execute</button>
48	  </div>
49	  <div class="form-group mt-1"><label>Reason (for rejection)</label><input id="exp-reason"></div>
50	  <div id="approval-result" class="mt-1"></div>
51	</div>
52	
53	<script>
54	const api=(u,b,m='POST')=>fetch(u,{method:m,headers:{'Content-Type':'application/json'},...(m==='GET'?{}:{body:JSON.stringify(b)})}).then(r=>r.json());
55	const showR=(el,d)=>{el.innerHTML=d.error?'<div class="msg msg-error">'+H(d.error.message)+'</div>':'<div class="msg msg-success">'+H(JSON.stringify(d.data,null,1))+'</div>';};
56	
57	document.getElementById('metrics-form').addEventListener('submit',async e=>{
58	  e.preventDefault();const fd=new FormData(e.target);
59	  let url='/api/exports/metrics?date_start='+encodeURIComponent(fd.get('date_start'))+'&date_end='+encodeURIComponent(fd.get('date_end'));
60	  const cat=fd.get('clothing_category');if(cat)url+='&clothing_category='+encodeURIComponent(cat);
61	  const r=await api(url,null,'GET');
62	  const el=document.getElementById('metrics-display');
63	  if(r.error){el.innerHTML='<div class="msg msg-error">'+H(r.error.message)+'</div>';return;}
64	  const m=r.data;
65	  el.innerHTML='<div class="metrics-grid">'
66	    +'<div class="metric-card"><div class="value">'+H(m.order_volume)+'</div><div class="label">Order Volume</div></div>'
67	    +'<div class="metric-card"><div class="value">$'+H(m.revenue.toFixed(2))+'</div><div class="label">Revenue</div></div>'
68	    +'<div class="metric-card"><div class="value">'+H(m.refund_rate.toFixed(1))+'%</div><div class="label">Refund Rate</div></div>'
69	    +'<div class="metric-card"><div class="value">'+H(m.load_factor.toFixed(1))+'%</div><div class="label">Load Factor</div></div>'
70	    +'</div>';
71	});
72	
73	document.getElementById('export-form').addEventListener('submit',async e=>{
74	  e.preventDefault();const fd=new FormData(e.target),b={};
75	  fd.forEach((v,k)=>b[k]=k==='watermark_enabled'?v==='true':v);
76	  showR(document.getElementById('export-result'),await api('/api/exports/requests',b));
77	});
78	
79	const eid=()=>document.getElementById('exp-id').value;
80	const apRes=()=>document.getElementById('approval-result');
81	const exportSummary=d=>'Export #'+H(d.id)+' — <span class="badge badge-'+H(d.status)+'">'+H(d.status)+'</span>';
82	
83	async function approveExport(){
84	  if (!eid()) { showMsg(apRes(),'error','Enter an export request ID.'); return; }
85	  const password=window.prompt('Re-enter your password to approve export request #'+eid()+':');
86	  if(!password)return;
87	  const r=await api('/api/exports/requests/'+eid()+'/approve',{password});
88	  showApiResult(apRes(),r,exportSummary);
89	}
90	async function rejectExport(){
91	  if (!eid()) { showMsg(apRes(),'error','Enter an export request ID.'); return; }
92	  const reason=document.getElementById('exp-reason').value.trim();
93	  if (!reason) { showMsg(apRes(),'error','Rejection reason is required.'); return; }
94	  if (!confirmAction('Reject export request #'+eid()+'?')) return;
95	  const r=await api('/api/exports/requests/'+eid()+'/reject',{reason});
96	  showApiResult(apRes(),r,exportSummary);
97	}
98	async function executeExport(){
99	  if (!eid()) { showMsg(apRes(),'error','Enter an export request ID.'); return; }
100	  if (!confirmAction('Execute export request #'+eid()+'? This is one-time only.')) return;
101	  const r=await api('/api/exports/requests/'+eid()+'/execute',{});
102	  showApiResult(apRes(),r,d=>exportSummary(d)+'<br>Completed at: '+H(d.completed_at||'—'));
103	}
104	</script>
105	{% endblock %}
