1	/* ReclaimOps — minimal operational UI */
2	*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
3	:root{--bg:#f5f5f5;--card:#fff;--border:#ddd;--primary:#2563eb;--danger:#dc2626;--success:#16a34a;--warn:#d97706;--muted:#6b7280;--text:#111;--radius:6px}
4	body{font-family:system-ui,-apple-system,sans-serif;background:var(--bg);color:var(--text);line-height:1.5;font-size:14px}
5	a{color:var(--primary);text-decoration:none}
6	a:hover{text-decoration:underline}
7	
8	/* layout */
9	.app-shell{display:flex;min-height:100vh}
10	.sidebar{width:220px;background:#1e293b;color:#e2e8f0;padding:1rem 0;flex-shrink:0}
11	.sidebar h2{padding:0 1rem 1rem;font-size:1rem;border-bottom:1px solid #334155;margin-bottom:.5rem}
12	.sidebar a{display:block;padding:.5rem 1rem;color:#cbd5e1;font-size:.875rem}
13	.sidebar a:hover,.sidebar a.active{background:#334155;color:#fff;text-decoration:none}
14	.main-content{flex:1;padding:1.5rem;max-width:1000px}
15	.main-content h1{font-size:1.25rem;margin-bottom:1rem;padding-bottom:.5rem;border-bottom:2px solid var(--primary)}
16	
17	/* cards */
18	.card{background:var(--card);border:1px solid var(--border);border-radius:var(--radius);padding:1rem;margin-bottom:1rem}
19	.card h3{font-size:.95rem;margin-bottom:.75rem;color:var(--primary)}
20	
21	/* forms */
22	.form-group{margin-bottom:.75rem}
23	.form-group label{display:block;font-weight:600;margin-bottom:.25rem;font-size:.8rem;color:var(--muted)}
24	.form-group input,.form-group select,.form-group textarea{width:100%;padding:.5rem;border:1px solid var(--border);border-radius:var(--radius);font-size:.875rem}
25	.form-group textarea{height:60px;resize:vertical}
26	.form-row{display:flex;gap:.75rem}
27	.form-row .form-group{flex:1}
28	
29	/* buttons */
30	.btn{display:inline-block;padding:.45rem .9rem;border:none;border-radius:var(--radius);font-size:.8rem;font-weight:600;cursor:pointer;text-align:center}
31	.btn-primary{background:var(--primary);color:#fff}
32	.btn-primary:hover{background:#1d4ed8}
33	.btn-danger{background:var(--danger);color:#fff}
34	.btn-danger:hover{background:#b91c1c}
35	.btn-success{background:var(--success);color:#fff}
36	.btn-warn{background:var(--warn);color:#fff}
37	.btn-sm{padding:.3rem .6rem;font-size:.75rem}
38	
39	/* status badges */
40	.badge{display:inline-block;padding:.15rem .5rem;border-radius:10px;font-size:.7rem;font-weight:700;text-transform:uppercase}
41	.badge-open{background:#dbeafe;color:#1e40af}
42	.badge-qc{background:#fef3c7;color:#92400e}
43	.badge-completed{background:#d1fae5;color:#065f46}
44	.badge-refunded{background:#fce7f3;color:#9d174d}
45	.badge-canceled{background:#f3f4f6;color:#6b7280}
46	.badge-pending{background:#fef3c7;color:#92400e}
47	.badge-approved{background:#d1fae5;color:#065f46}
48	.badge-rejected{background:#fee2e2;color:#991b1b}
49	.badge-available{background:#d1fae5;color:#065f46}
50	.badge-occupied{background:#dbeafe;color:#1e40af}
51	.badge-pre_checkout{background:#fef3c7;color:#92400e}
52	.badge-cleared{background:#f3f4f6;color:#6b7280}
53	.badge-pass{background:#d1fae5;color:#065f46}
54	.badge-fail{background:#fee2e2;color:#991b1b}
55	
56	/* messages */
57	.msg{padding:.6rem .9rem;border-radius:var(--radius);margin-bottom:.75rem;font-size:.85rem}
58	.msg-success{background:#d1fae5;color:#065f46;border:1px solid #6ee7b7}
59	.msg-error{background:#fee2e2;color:#991b1b;border:1px solid #fca5a5}
60	.msg-info{background:#dbeafe;color:#1e40af;border:1px solid #93c5fd}
61	
62	/* tables */
63	table{width:100%;border-collapse:collapse;font-size:.85rem}
64	th,td{text-align:left;padding:.5rem;border-bottom:1px solid var(--border)}
65	th{background:#f8fafc;font-weight:600;color:var(--muted);font-size:.75rem;text-transform:uppercase}
66	
67	/* grid for table/room cards */
68	.table-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(180px,1fr));gap:.75rem}
69	.table-card{background:var(--card);border:2px solid var(--border);border-radius:var(--radius);padding:.75rem;text-align:center;cursor:pointer;transition:border-color .15s}
70	.table-card:hover{border-color:var(--primary)}
71	.table-card.occupied{border-color:var(--primary);background:#eff6ff}
72	.table-card.pre_checkout{border-color:var(--warn);background:#fffbeb}
73	.table-card.cleared{border-color:var(--muted);background:#f9fafb}
74	
75	/* timeline */
76	.timeline{border-left:2px solid var(--border);padding-left:1rem;margin:.5rem 0}
77	.timeline-item{position:relative;padding-bottom:.75rem;font-size:.8rem}
78	.timeline-item::before{content:'';position:absolute;left:-1.35rem;top:.3rem;width:10px;height:10px;border-radius:50%;background:var(--primary);border:2px solid var(--card)}
79	.timeline-item .ts{color:var(--muted);font-size:.7rem}
80	
81	/* metrics */
82	.metrics-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));gap:.75rem;margin-bottom:1rem}
83	.metric-card{background:var(--card);border:1px solid var(--border);border-radius:var(--radius);padding:1rem;text-align:center}
84	.metric-card .value{font-size:1.5rem;font-weight:700;color:var(--primary)}
85	.metric-card .label{font-size:.75rem;color:var(--muted);text-transform:uppercase}
86	
87	/* login */
88	.login-container{max-width:360px;margin:6rem auto;padding:2rem}
89	.login-container h1{text-align:center;margin-bottom:1.5rem}
90	
91	/* utility */
92	.mt-1{margin-top:.5rem}.mt-2{margin-top:1rem}
93	.mb-1{margin-bottom:.5rem}.mb-2{margin-bottom:1rem}
94	.text-muted{color:var(--muted)}
95	.text-sm{font-size:.8rem}
96	.hidden{display:none}
97	#result{min-height:1.5rem}
98	
99	/* focus rings — accessibility polish */
100	.form-group input:focus,.form-group select:focus,.form-group textarea:focus{
101	  outline:none;border-color:var(--primary);box-shadow:0 0 0 3px rgba(37,99,235,.15)
102	}
103	.btn:focus{outline:none;box-shadow:0 0 0 3px rgba(37,99,235,.25)}
104	
105	/* disabled / submitting states */
106	.btn:disabled,.btn.is-loading{opacity:.55;cursor:not-allowed;pointer-events:none}
107	.btn.is-loading::after{
108	  content:'';display:inline-block;margin-left:.5rem;width:.75rem;height:.75rem;
109	  border:2px solid currentColor;border-top-color:transparent;border-radius:50%;
110	  animation:spin .7s linear infinite;vertical-align:-2px
111	}
112	@keyframes spin{to{transform:rotate(360deg)}}
113	
114	/* HTMX request indicator */
115	.htmx-indicator{display:none;color:var(--muted);font-size:.75rem;margin-left:.5rem}
116	.htmx-request .htmx-indicator,.htmx-request.htmx-indicator{display:inline}
117	.htmx-request .btn{opacity:.55;pointer-events:none}
118	
119	/* form-group hint text */
120	.hint{display:block;color:var(--muted);font-size:.7rem;margin-top:.2rem}
121	
122	/* sidebar refinement */
123	.sidebar a{border-left:3px solid transparent;transition:background .1s,border-color .1s}
124	.sidebar a:hover{border-left-color:var(--primary)}
