    <button class="btn btn-sm" style="background:#6b7280;color:#fff" onclick="showCancelForm()">Cancel</button>
  </div>
  <div id="action-result" class="mt-1"></div>

  <div id="variance-form" class="hidden mt-2 card">
    <h3>Confirm Variance</h3>
    <div class="form-group"><label>Confirmation Note</label><textarea id="variance-note" required></textarea></div>
    <button class="btn btn-warn" onclick="confirmVariance()">Confirm</button>
  </div>

  <div id="variance-approval" class="hidden mt-2 card">
    <h3>Supervisor Variance Approval</h3>
    <div class="form-group"><label>Approval Request ID</label><input id="var-req-id" type="number"></div>
    <div style="display:flex;gap:.5rem">
      <button class="btn btn-success" onclick="approveVariance()">Approve (Password)</button>
      <button class="btn btn-danger" onclick="rejectVariance()">Reject</button>
    </div>
    <div class="form-group mt-1"><label>Reason (for rejection)</label><input id="var-reject-reason"></div>
  </div>

  <div id="refund-form" class="hidden mt-2 card">
    <h3>Initiate Refund</h3>
    <div class="form-row">
      <div class="form-group"><label>Amount (blank = full)</label><input id="refund-amount" type="number" step="0.01"></div>
      <div class="form-group"><label>Reason</label><input id="refund-reason"></div>
    </div>
    <button class="btn btn-danger" onclick="initiateRefund()">Submit Refund Request</button>
