<script>
const api = (url, body) => fetch(url, {method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(body)}).then(r=>r.json());
const show = (id) => document.getElementById(id).classList.remove('hidden');
const tid = () => parseInt(document.getElementById('action-ticket-id').value);
const actionResult = () => document.getElementById('action-result');
const refreshQueue = () => htmx.trigger('#ticket-queue', 'load');

function requireTicketId() {
  const v = tid();
  if (!Number.isFinite(v) || v <= 0) {
    showMsg(actionResult(), 'error', 'Enter a ticket ID first.');
    return null;
  }
  return v;
}

function ticketSummary(t) {
  return 'Ticket #' + H(t.id) + ' — <span class="badge badge-' + H(t.status) + '">' + H(t.status) + '</span>';
}

document.getElementById('ticket-form').addEventListener('submit', async (e) => {
  e.preventDefault();
  const btn = e.target.querySelector('button[type="submit"]');
  btn.classList.add('is-loading');
  try {
    const fd = new FormData(e.target);
    const body = {};
    fd.forEach((v,k) => { if(v) body[k] = k === 'estimated_weight_lbs' ? Number(v) : v; });
    const r = await api('/api/tickets', body);
    const el = document.getElementById('ticket-result');
    if (r.error) { showMsg(el, 'error', escapeHtml(r.error.message)); return; }
    const t = r.data;
    el.innerHTML = '<div class="msg msg-success">'
      + 'Ticket #' + H(t.id) + ' created — <span class="badge badge-' + H(t.status) + '">' + H(t.status) + '</span><br>'
      + '<strong>Estimated Payout: $' + H((t.estimated_payout || 0).toFixed(2)) + '</strong>'
      + (t.estimated_cap_applied ? ' <em>(cap applied)</em>' : '')
      + '</div>';
    refreshQueue();
    e.target.reset();
  } finally { btn.classList.remove('is-loading'); }
});

// Queue inline actions
function cancelFromQueue(id) {
  const reason = window.prompt('Cancellation reason for ticket #' + id + ':');
  if (!reason) return;
  api('/api/tickets/' + id + '/cancel', {reason}).then(r => {
    if (r.error) showMsg(actionResult(), 'error', H(r.error.message));
    refreshQueue();
  });
}
function confirmVarianceFromQueue(id) {
  document.getElementById('action-ticket-id').value = id;
  showVarianceConfirm();
}
function dialFromQueue(id) {
  if (!confirmAction('Dial customer for ticket #' + id + '? This action is audited.')) return;
  api('/api/tickets/' + id + '/dial', {}).then(r => {
    if (r.error) { showMsg(actionResult(), 'error', H(r.error.message)); return; }
    const phone = r.data.phone;
    showMsg(actionResult(), 'success',
      'Dialing: <a href="tel:' + H(phone) + '" class="btn btn-success btn-sm" style="text-decoration:none">Call ' + H(r.data.last4 ? '••••' + r.data.last4 : phone) + '</a> (audit logged)');
  });
}

function showVarianceConfirm() { show('variance-form'); show('variance-approval'); }
function showRefundForm() { show('refund-form'); }
function showCancelForm() { show('cancel-form'); }

async function confirmVariance() {
  if (!requireTicketId()) return;
  const note = document.getElementById('variance-note').value.trim();
  if (!note) { showMsg(actionResult(), 'error', 'Confirmation note is required.'); return; }
  const r = await api('/api/tickets/' + tid() + '/confirm-variance', {confirmation_note: note});
  showApiResult(actionResult(), r, d => 'Variance confirmed — approval request #' + d.id);
  if (r.data) document.getElementById('var-req-id').value = r.data.id;
  refreshQueue();
}

async function approveVariance() {
  const rid = document.getElementById('var-req-id').value;
  if (!rid) { showMsg(actionResult(), 'error', 'Enter an approval request ID.'); return; }
  const password = window.prompt('Re-enter your password to approve this variance:');
  if (!password) return;
  const r = await api('/api/tickets/variance/' + rid + '/approve', {password});
  showApiResult(actionResult(), r, ticketSummary);
  refreshQueue();
}

async function rejectVariance() {
  const rid = document.getElementById('var-req-id').value;
  if (!rid) { showMsg(actionResult(), 'error', 'Enter an approval request ID.'); return; }
  const reason = document.getElementById('var-reject-reason').value.trim();
  if (!reason) { showMsg(actionResult(), 'error', 'Rejection reason is required.'); return; }
  if (!confirmAction('Reject this variance approval? This cannot be undone.')) return;
  const r = await api('/api/tickets/variance/' + rid + '/reject', {reason});
  showApiResult(actionResult(), r, d => 'Variance rejected — request #' + d.id);
  refreshQueue();
}

async function initiateRefund() {
  if (!requireTicketId()) return;
  const body = {};
  const amt = document.getElementById('refund-amount').value;
  if (amt) {
    const reason = document.getElementById('refund-reason').value.trim();
    if (!reason) { showMsg(actionResult(), 'error', 'Reason required for partial refund.'); return; }
    body.refund_amount = parseFloat(amt);
    body.reason = reason;
  }
  if (!confirmAction('Submit a refund request for ticket #' + tid() + '?')) return;
  const r = await api('/api/tickets/' + tid() + '/refund', body);
  showApiResult(actionResult(), r, ticketSummary);
  refreshQueue();
}

async function approveRefund() {
  const id = document.getElementById('refund-approve-id').value;
  if (!id) { showMsg(actionResult(), 'error', 'Enter a ticket ID.'); return; }
  const password = window.prompt('Re-enter your password to approve refund for ticket #' + id + ':');
  if (!password) return;
  const r = await api('/api/tickets/' + id + '/refund/approve', {password});
  showApiResult(actionResult(), r, ticketSummary);
  refreshQueue();
}

async function rejectRefund() {
  const id = document.getElementById('refund-approve-id').value;
  if (!id) { showMsg(actionResult(), 'error', 'Enter a ticket ID.'); return; }
  const reason = document.getElementById('refund-reject-reason').value.trim();
  if (!reason) { showMsg(actionResult(), 'error', 'Rejection reason is required.'); return; }
  if (!confirmAction('Reject refund for ticket #' + id + '?')) return;
  const r = await api('/api/tickets/' + id + '/refund/reject', {reason});
  showApiResult(actionResult(), r, ticketSummary);
  refreshQueue();
}

async function cancelTicket() {
  if (!requireTicketId()) return;
  const reason = document.getElementById('cancel-reason').value.trim();
  if (!reason) { showMsg(actionResult(), 'error', 'Cancellation reason is required.'); return; }
  if (!confirmAction('Cancel ticket #' + tid() + '? This cannot be undone.')) return;
  const r = await api('/api/tickets/' + tid() + '/cancel', {reason});
  showApiResult(actionResult(), r, ticketSummary);
  refreshQueue();
}
</script>
{% endblock %}
