{% block title %}QC & Traceability{% endblock %}
{% block content %}
<h1>Quality Control &amp; Traceability</h1>

<div class="card">
  <h3>QC Work Queue</h3>
  <button class="btn btn-sm btn-primary" hx-get="/ui/partials/qc/queue" hx-target="#qc-queue" hx-swap="innerHTML">Refresh</button>
  <div id="qc-queue" class="mt-1"
       hx-get="/ui/partials/qc/queue"
       hx-trigger="load"
       hx-swap="innerHTML">
    <div class="msg msg-info">Loading QC queue...</div>
  </div>
</div>

<div class="card">
  <h3>Create QC Inspection</h3>
  <div id="qc-result"></div>
  <form id="qc-form">
    <div class="form-row">
      <div class="form-group"><label>Ticket ID</label><input name="ticket_id" type="number" required></div>
    </div>
    <div class="form-row">
      <div class="form-group"><label>Actual Weight (lbs)</label><input name="actual_weight_lbs" type="number" step="0.1" required></div>
      <div class="form-group"><label>Lot Size</label><input name="lot_size" type="number" value="10" required></div>
    </div>
    <div class="form-row">
      <div class="form-group"><label>Nonconformances</label><input name="nonconformance_count" type="number" value="0" required></div>
      <div class="form-group"><label>Outcome</label>
        <select name="inspection_outcome" required>
          <option value="pass">Pass</option><option value="fail">Fail</option><option value="pass_with_concession">Pass with Concession</option>
        </select>
      </div>
    </div>
    <div class="form-group"><label>Notes</label><textarea name="notes"></textarea></div>
    <button type="submit" class="btn btn-primary">Record Inspection</button>
  </form>
</div>

<div class="card">
  <h3>Compute Final Payout</h3>
  <p class="text-sm text-muted">Weight is taken from the QC inspection record. Optional field is a safety cross-check only.</p>
  <form id="qc-final-form">
    <div class="form-row">
      <div class="form-group"><label>Ticket ID</label><input name="ticket_id" type="number" required></div>
      <div class="form-group"><label>Weight Cross-Check (optional)</label><input name="actual_weight_lbs" type="number" step="0.1" placeholder="Leave blank to use QC value"></div>
    </div>
    <button type="submit" class="btn btn-primary">Compute Final Payout</button>
  </form>
  <div id="qc-final-result" class="mt-1"></div>
</div>

<div class="card">
  <h3>Quarantine</h3>
  <div class="form-row">
    <div class="form-group"><label>Ticket ID</label><input id="q-ticket" type="number"></div>
    <div class="form-group"><label>Batch ID</label><input id="q-batch" type="number"></div>
  </div>
  <button class="btn btn-warn btn-sm" onclick="createQuarantine()">Create Quarantine</button>
  <div class="mt-1">
    <div class="form-row">
      <div class="form-group"><label>Quarantine ID</label><input id="q-id" type="number"></div>
      <div class="form-group"><label>Disposition</label>
        <select id="q-disp"><option value="return_to_customer">Return to Customer</option><option value="scrap">Scrap</option><option value="concession_acceptance">Concession Acceptance</option></select>
      </div>
