{% block title %}Tables / Rooms{% endblock %}
{% block content %}
<h1>Tables / Rooms</h1>

<div class="card">
  <h3>Open Table</h3>
  <form id="open-form">
    <div class="form-row">
      <div class="form-group"><label>Table ID</label><input name="table_id" type="number" required></div>
      <div class="form-group"><label>Customer Label</label><input name="customer_label" placeholder="Optional"></div>
    </div>
    <button type="submit" class="btn btn-primary">Open Table</button>
  </form>
  <div id="open-result" class="mt-1"></div>
</div>

<div class="card">
  <h3>Session Board</h3>
  <button class="btn btn-sm btn-primary" hx-get="/ui/partials/tables/board" hx-target="#table-board" hx-swap="innerHTML">Refresh</button>
  <div id="table-board" class="mt-1"
       hx-get="/ui/partials/tables/board"
       hx-trigger="load"
       hx-swap="innerHTML">
    <div class="msg msg-info">Loading table sessions...</div>
  </div>
</div>

<div class="card">
  <h3>Merge / Transfer</h3>
  <div class="form-row">
    <div class="form-group"><label>Session IDs (comma-sep)</label><input id="merge-ids" placeholder="1,2,3"></div>
    <div class="form-group"><label>Store ID</label><input id="merge-store" type="number" value="1"></div>
  </div>
  <button class="btn btn-warn btn-sm" onclick="mergeTables()">Merge</button>
  <div class="form-row mt-1">
    <div class="form-group"><label>Session ID</label><input id="transfer-session" type="number"></div>
    <div class="form-group"><label>New User ID</label><input id="transfer-user" type="number"></div>
  </div>
  <button class="btn btn-sm btn-primary" onclick="transferTable()">Transfer</button>
  <div id="action-result" class="mt-1"></div>
</div>

<div class="card">
  <h3>Activity Timeline</h3>
  <div class="form-row">
    <div class="form-group"><label>Session ID</label><input id="timeline-session" type="number"></div>
    <div class="form-group" style="padding-top:1.2rem">
      <button class="btn btn-sm btn-primary"
              hx-get="/ui/partials/tables/board"
              hx-target="#timeline-display"
              onclick="loadTimeline(); return false;">Load</button>
    </div>
  </div>
  <div id="timeline-display"></div>
</div>

<script>
const api = (url, body, method='POST') => fetch(url, {method,headers:{'Content-Type':'application/json'},...(method==='GET'?{}:{body:JSON.stringify(body)})}).then(r=>r.json());
const showR = (el, d) => { el.innerHTML = d.error ? '<div class="msg msg-error">'+H(d.error.message)+'</div>' : '<div class="msg msg-success">'+H(JSON.stringify(d.data,null,1))+'</div>'; };
const refreshBoard = () => htmx.trigger('#table-board', 'load');

document.getElementById('open-form').addEventListener('submit', async e => {
  e.preventDefault(); const fd = new FormData(e.target), b = {};
  fd.forEach((v,k)=>b[k]=['table_id','store_id'].includes(k)?+v:v);
  const r = await api('/api/tables/open', b);
  showR(document.getElementById('open-result'), r);
  refreshBoard();
});

async function mergeTables(){
  const ids=document.getElementById('merge-ids').value.split(',').map(s=>parseInt(s.trim())).filter(n=>!isNaN(n));
  if(ids.length<2){showMsg(document.getElementById('action-result'),'error','Enter at least 2 session IDs.');return;}
  showR(document.getElementById('action-result'),await api('/api/tables/merge',{session_ids:ids,store_id:+document.getElementById('merge-store').value}));
  refreshBoard();
}
async function transferTable(){
  const sid=document.getElementById('transfer-session').value;
  const uid=document.getElementById('transfer-user').value;
  if(!sid||!uid){showMsg(document.getElementById('action-result'),'error','Session ID and User ID required.');return;}
  showR(document.getElementById('action-result'),await api('/api/tables/sessions/'+sid+'/transfer',{new_user_id:+uid}));
  refreshBoard();
}
async function loadTimeline(){
  const sid=document.getElementById('timeline-session').value;
  if(!sid)return;
  const r=await api('/api/tables/sessions/'+sid+'/timeline',null,'GET');
  const el=document.getElementById('timeline-display');
  if(r.error){el.innerHTML='<div class="msg msg-error">'+H(r.error.message)+'</div>';return;}
  if(!r.data?.length){el.innerHTML='<div class="msg msg-info">No events</div>';return;}
  el.innerHTML='<div class="timeline">'+r.data.map(e=>'<div class="timeline-item"><strong>'+H(e.event_type)+'</strong> '+H(e.before_state||'')+'→'+H(e.after_state||'')+' <span class="ts">'+H(e.created_at)+'</span>'+(e.notes?'<br><span class="text-sm">'+H(e.notes)+'</span>':'')+'</div>').join('')+'</div>';
}
</script>
{% endblock %}
"}

