document.getElementById('open-form').addEventListener('submit', async e => {
  e.preventDefault(); const fd = new FormData(e.target), b = {};
  fd.forEach((v,k)=>b[k]=['table_id','store_id'].includes(k)?+v:v);
  const r = await api('/api/tables/open', b);
  showR(document.getElementById('open-result'), r);
  refreshBoard();
});

async function mergeTables(){
  const ids=document.getElementById('merge-ids').value.split(',').map(s=>parseInt(s.trim())).filter(n=>!isNaN(n));
  if(ids.length<2){showMsg(document.getElementById('action-result'),'error','Enter at least 2 session IDs.');return;}
  showR(document.getElementById('action-result'),await api('/api/tables/merge',{session_ids:ids,store_id:+document.getElementById('merge-store').value}));
  refreshBoard();
}
async function transferTable(){
  const sid=document.getElementById('transfer-session').value;
  const uid=document.getElementById('transfer-user').value;
  if(!sid||!uid){showMsg(document.getElementById('action-result'),'error','Session ID and User ID required.');return;}
  showR(document.getElementById('action-result'),await api('/api/tables/sessions/'+sid+'/transfer',{new_user_id:+uid}));
  refreshBoard();
}
async function loadTimeline(){
  const sid=document.getElementById('timeline-session').value;
  if(!sid)return;
  const r=await api('/api/tables/sessions/'+sid+'/timeline',null,'GET');
  const el=document.getElementById('timeline-display');
  if(r.error){el.innerHTML='<div class="msg msg-error">'+H(r.error.message)+'</div>';return;}
  if(!r.data?.length){el.innerHTML='<div class="msg msg-info">No events</div>';return;}
  el.innerHTML='<div class="timeline">'+r.data.map(e=>'<div class="timeline-item"><strong>'+H(e.event_type)+'</strong> '+H(e.before_state||'')+'→'+H(e.after_state||'')+' <span class="ts">'+H(e.created_at)+'</span>'+(e.notes?'<br><span class="text-sm">'+H(e.notes)+'</span>':'')+'</div>').join('')+'</div>';
}
</script>
{% endblock %}
"}

