15	    </div>
16	    <div class="form-group"><label>Message Body</label><textarea name="message_body" required></textarea></div>
17	    <div class="form-row">
18	      <div class="form-group"><label>Call Status (if phone)</label>
19	        <select name="call_attempt_status"><option value="">N/A</option><option value="succeeded">Succeeded</option><option value="failed">Failed</option><option value="voicemail">Voicemail</option><option value="no_answer">No Answer</option></select>
20	      </div>
21	      <div class="form-group"><label>Retry in (minutes)</label><input name="retry_minutes" type="number"></div>
22	    </div>
23	    <button type="submit" class="btn btn-primary">Log</button>
24	  </form>
25	</div>
26	
27	<div class="card">
28	  <h3>Send from Template</h3>
29	  <form id="tpl-form">
30	    <div class="form-row">
31	      <div class="form-group"><label>Ticket ID</label><input name="ticket_id" type="number" required></div>
32	      <div class="form-group"><label>Template Code</label>
33	        <select name="template_code"><option>accepted</option><option>rescheduled</option><option>arrived</option><option>completed</option><option>refunded</option></select>
34	      </div>
35	      <!-- store_id is derived from the session -->
36	    </div>
37	    <div class="form-group"><label>Context JSON</label><input name="context" value='{"customer_name":"Customer"}' style="font-family:monospace"></div>
38	    <button type="submit" class="btn btn-primary">Send Template</button>
39	  </form>
40	  <div id="tpl-result" class="mt-1"></div>
41	</div>
42	
43	<div class="card">
44	  <h3>Message History</h3>
45	  <div class="form-row">
46	    <div class="form-group"><label>Ticket ID</label><input id="hist-ticket" type="number"></div>
47	    <div class="form-group" style="padding-top:1.2rem"><button class="btn btn-primary btn-sm" onclick="loadHistory()">Load</button></div>
48	  </div>
49	  <div id="history-list"></div>
50	</div>
51	
52	<div class="card">
53	  <h3>Pending Retries</h3>
