66	document.getElementById('msg-form').addEventListener('submit',async e=>{
67	  e.preventDefault();const fd=new FormData(e.target),b={};
68	  fd.forEach((v,k)=>{if(!v)return;b[k]=['ticket_id','retry_minutes'].includes(k)?+v:v;});
