1	{% extends "base.html" %}
2	{% block title %}Reports & Exports{% endblock %}
3	{% block content %}
4	<h1>Reports &amp; Exports</h1>
5	
6	<div class="card">
7	  <h3>Operations Metrics</h3>
8	  <form id="metrics-form" hx-target="#metrics-display">
9	    <div class="form-row">
10	      <div class="form-group"><label>Date Start</label><input name="date_start" type="date" required></div>
11	      <div class="form-group"><label>Date End</label><input name="date_end" type="date" required></div>
12	      <div class="form-group"><label>Category Filter</label>
13	        <select name="clothing_category"><option value="">All</option><option>shirts</option><option>pants</option><option>jackets</option><option>dresses</option><option>mixed</option></select>
14	      </div>
15	      <div class="form-group"><label>Route Code</label>
16	        <input name="route_code" placeholder="Filter by route">
17	      </div>
18	    </div>
19	    <button type="submit" class="btn btn-primary">Load Metrics</button>
20	  </form>
21	  <div id="metrics-display" class="mt-1"></div>
22	</div>
23	
24	<div class="card">
25	  <h3>Request Export</h3>
26	  <div id="export-result"></div>
27	  <form id="export-form">
28	    <div class="form-row">
29	      <!-- store_id is derived from the session -->
30	      <div class="form-group"><label>Export Type</label>
31	        <select name="export_type"><option>tickets</option><option>metrics</option></select>
32	      </div>
33	    </div>
34	    <div class="form-row">
35	      <div class="form-group"><label>Watermark</label><select name="watermark_enabled"><option value="false">No</option><option value="true">Yes</option></select></div>
36	      <div class="form-group"><label>Attribution</label><input name="attribution_text" placeholder="Optional"></div>
37	    </div>
38	    <button type="submit" class="btn btn-primary">Request Export</button>
39	  </form>
40	</div>
41	
42	<div class="card">
43	  <h3>Export Approval (Supervisor)</h3>
44	  <div class="form-row">
45	    <div class="form-group"><label>Request ID</label><input id="exp-id" type="number"></div>
46	  </div>
47	  <div style="display:flex;gap:.5rem">
48	    <button class="btn btn-success btn-sm" onclick="approveExport()">Approve</button>
49	    <button class="btn btn-danger btn-sm" onclick="rejectExport()">Reject</button>
50	    <button class="btn btn-primary btn-sm" onclick="executeExport()">Execute</button>
51	  </div>
52	  <div class="form-group mt-1"><label>Reason (for rejection)</label><input id="exp-reason"></div>
53	  <div id="approval-result" class="mt-1"></div>
54	</div>
55	
56	<script>
57	const api=(u,b,m='POST')=>fetch(u,{method:m,headers:{'Content-Type':'application/json'},...(m==='GET'?{}:{body:JSON.stringify(b)})}).then(r=>r.json());
58	const showR=(el,d)=>{el.innerHTML=d.error?'<div class="msg msg-error">'+H(d.error.message)+'</div>':'<div class="msg msg-success">'+H(JSON.stringify(d.data,null,1))+'</div>';};
59	
60	document.getElementById('metrics-form').addEventListener('submit',async e=>{
61	  e.preventDefault();const fd=new FormData(e.target);
62	  let url='/api/exports/metrics?date_start='+encodeURIComponent(fd.get('date_start'))+'&date_end='+encodeURIComponent(fd.get('date_end'));
63	  const cat=fd.get('clothing_category');if(cat)url+='&clothing_category='+encodeURIComponent(cat);
64	  const rc=fd.get('route_code');if(rc)url+='&route_code='+encodeURIComponent(rc);
65	  const r=await api(url,null,'GET');
66	  const el=document.getElementById('metrics-display');
67	  if(r.error){el.innerHTML='<div class="msg msg-error">'+H(r.error.message)+'</div>';return;}
68	  const m=r.data;
69	  el.innerHTML='<div class="metrics-grid">'
70	    +'<div class="metric-card"><div class="value">'+H(m.order_volume)+'</div><div class="label">Order Volume</div></div>'
71	    +'<div class="metric-card"><div class="value">$'+H(m.revenue.toFixed(2))+'</div><div class="label">Revenue</div></div>'
72	    +'<div class="metric-card"><div class="value">'+H(m.refund_rate.toFixed(1))+'%</div><div class="label">Refund Rate</div></div>'
73	    +'<div class="metric-card"><div class="value">'+H(m.load_factor.toFixed(1))+'%</div><div class="label">Load Factor</div></div>'
74	    +'</div>'
75	    +(m.route_code?'<div class="text-sm text-muted mt-1">Route: '+H(m.route_code)+' ('+H(m.stores_in_route?.length||0)+' stores)</div>':'');
76	});
77	
78	document.getElementById('export-form').addEventListener('submit',async e=>{
79	  e.preventDefault();const fd=new FormData(e.target),b={};
80	  fd.forEach((v,k)=>b[k]=k==='watermark_enabled'?v==='true':v);
81	  showR(document.getElementById('export-result'),await api('/api/exports/requests',b));
82	});
83	
84	const eid=()=>document.getElementById('exp-id').value;
85	const apRes=()=>document.getElementById('approval-result');
86	const exportSummary=d=>'Export #'+H(d.id)+' — <span class="badge badge-'+H(d.status)+'">'+H(d.status)+'</span>';
87	
88	async function approveExport(){
89	  if (!eid()) { showMsg(apRes(),'error','Enter an export request ID.'); return; }
90	  const password=window.prompt('Re-enter your password to approve export request #'+eid()+':');
91	  if(!password)return;
92	  const r=await api('/api/exports/requests/'+eid()+'/approve',{password});
93	  showApiResult(apRes(),r,exportSummary);
94	}
95	async function rejectExport(){
96	  if (!eid()) { showMsg(apRes(),'error','Enter an export request ID.'); return; }
97	  const reason=document.getElementById('exp-reason').value.trim();
98	  if (!reason) { showMsg(apRes(),'error','Rejection reason is required.'); return; }
99	  if (!confirmAction('Reject export request #'+eid()+'?')) return;
100	  const r=await api('/api/exports/requests/'+eid()+'/reject',{reason});
101	  showApiResult(apRes(),r,exportSummary);
102	}
103	async function executeExport(){
104	  if (!eid()) { showMsg(apRes(),'error','Enter an export request ID.'); return; }
105	  if (!confirmAction('Execute export request #'+eid()+'? This is one-time only.')) return;
106	  const r=await api('/api/exports/requests/'+eid()+'/execute',{});
107	  showApiResult(apRes(),r,d=>exportSummary(d)+'<br>Completed at: '+H(d.completed_at||'—'));
108	}
109	</script>
110	{% endblock %}
111

