28	
29	<div class="card">
30	  <h3>Pending Adjustments</h3>
31	  <button class="btn btn-primary btn-sm" onclick="loadPending()">Refresh</button>
32	  <div id="pending-list" class="mt-1"></div>
33	</div>
34	
35	<div class="card">
36	  <h3>Supervisor Actions</h3>
37	  <div class="form-row">
38	    <div class="form-group"><label>Request ID</label><input id="adj-id" type="number"></div>
39	  </div>
