1	{% extends "base.html" %}
2	{% block title %}Tickets{% endblock %}
3	{% block content %}
4	<h1>Buyback Tickets</h1>
5	
6	<div class="card">
7	  <h3>Create New Ticket</h3>
8	  <div id="ticket-result"></div>
9	  <form id="ticket-form" hx-target="#ticket-result">
10	    <div class="form-row">
11	      <div class="form-group"><label>Customer Name</label><input name="customer_name" required></div>
12	      <div class="form-group"><label>Customer Phone</label><input name="customer_phone" type="tel" placeholder="Full number — encrypted at rest"></div>
13	    </div>
14	    <div class="form-row">
15	      <div class="form-group"><label>Category</label>
16	        <select name="clothing_category" required>
17	          <option value="">Select...</option><option>shirts</option><option>pants</option><option>jackets</option><option>dresses</option><option>mixed</option>
18	        </select>
19	      </div>
20	      <div class="form-group"><label>Condition Grade</label>
21	        <select name="condition_grade" required>
22	          <option value="">Select...</option><option value="A">A — Excellent</option><option value="B">B — Good</option><option value="C">C — Fair</option>
23	        </select>
24	      </div>
25	    </div>
26	    <div class="form-row">
27	      <div class="form-group"><label>Estimated Weight (lbs)</label><input name="estimated_weight_lbs" type="number" step="0.1" min="0.1" required></div>
28	      <div class="form-group"><label>Phone Preference</label>
29	        <select name="customer_phone_preference"><option value="standard_calls">Standard</option><option value="calls_only">Calls Only</option></select>
30	      </div>
31	    </div>
32	    <button type="submit" class="btn btn-primary">Create Ticket &amp; Calculate Payout</button>
33	  </form>
34	</div>
35	
36	<div class="card">
37	  <h3>Ticket Queue</h3>
38	  <button class="btn btn-sm btn-primary" hx-get="/ui/partials/tickets/queue" hx-target="#ticket-queue" hx-swap="innerHTML">Refresh</button>
39	  <span class="htmx-indicator">Loading...</span>
40	  <div id="ticket-queue" class="mt-1"
41	       hx-get="/ui/partials/tickets/queue"
42	       hx-trigger="load"
43	       hx-swap="innerHTML">
44	    <div class="msg msg-info">Loading ticket queue...</div>
45	  </div>
46	</div>
47	
48	<div class="card">
49	  <h3>Supervisor Actions</h3>
50	  <div class="form-row">
51	    <div class="form-group"><label>Ticket / Request ID</label><input id="action-ticket-id" type="number" placeholder="Enter ID"></div>
52	  </div>
53	  <div style="display:flex;gap:.5rem;flex-wrap:wrap">
54	    <button class="btn btn-warn btn-sm" onclick="showVarianceConfirm()">Confirm Variance</button>
55	    <button class="btn btn-danger btn-sm" onclick="showRefundForm()">Initiate Refund</button>
56	    <button class="btn btn-sm" style="background:#6b7280;color:#fff" onclick="showCancelForm()">Cancel</button>
57	  </div>
58	  <div id="action-result" class="mt-1"></div>
59	
60	  <div id="variance-form" class="hidden mt-2 card">
61	    <h3>Confirm Variance</h3>
62	    <div class="form-group"><label>Confirmation Note</label><textarea id="variance-note" required></textarea></div>
63	    <button class="btn btn-warn" onclick="confirmVariance()">Confirm</button>
64	  </div>
65	
66	  <div id="variance-approval" class="hidden mt-2 card">
67	    <h3>Supervisor Variance Approval</h3>
68	    <div class="form-group"><label>Approval Request ID</label><input id="var-req-id" type="number"></div>
69	    <div style="display:flex;gap:.5rem">
70	      <button class="btn btn-success" onclick="approveVariance()">Approve (Password)</button>
71	      <button class="btn btn-danger" onclick="rejectVariance()">Reject</button>
72	    </div>
73	    <div class="form-group mt-1"><label>Reason (for rejection)</label><input id="var-reject-reason"></div>
74	  </div>
75	
76	  <div id="refund-form" class="hidden mt-2 card">
77	    <h3>Initiate Refund</h3>
78	    <div class="form-row">
79	      <div class="form-group"><label>Amount (blank = full)</label><input id="refund-amount" type="number" step="0.01"></div>
80	      <div class="form-group"><label>Reason</label><input id="refund-reason"></div>
81	    </div>
82	    <button class="btn btn-danger" onclick="initiateRefund()">Submit Refund Request</button>
83	  </div>
84	
85	  <div id="refund-approval" class="mt-2 card">
86	    <h3>Refund Approval (Supervisor)</h3>
87	    <div class="form-group"><label>Ticket ID</label><input id="refund-approve-id" type="number"></div>
88	    <div style="display:flex;gap:.5rem">
89	      <button class="btn btn-success" onclick="approveRefund()">Approve Refund</button>
90	      <button class="btn btn-danger" onclick="rejectRefund()">Reject Refund</button>
91	    </div>
92	    <div class="form-group mt-1"><label>Reason (for rejection)</label><input id="refund-reject-reason"></div>
93	  </div>
94	
95	  <div id="cancel-form" class="hidden mt-2 card">
96	    <h3>Cancel Ticket</h3>
97	    <div class="form-group"><label>Reason</label><input id="cancel-reason" required></div>
98	    <button class="btn btn-danger" onclick="cancelTicket()">Cancel Ticket</button>
99	  </div>
100	</div>
101	
102	<script>
103	const api = (url, body) => fetch(url, {method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(body)}).then(r=>r.json());
104	const show = (id) => document.getElementById(id).classList.remove('hidden');
105	const tid = () => parseInt(document.getElementById('action-ticket-id').value);
106	const actionResult = () => document.getElementById('action-result');
107	const refreshQueue = () => htmx.trigger('#ticket-queue', 'load');
108	
109	function requireTicketId() {
110	  const v = tid();
111	  if (!Number.isFinite(v) || v <= 0) {
112	    showMsg(actionResult(), 'error', 'Enter a ticket ID first.');
113	    return null;
114	  }
115	  return v;
116	}
117	
118	function ticketSummary(t) {
119	  return 'Ticket #' + H(t.id) + ' — <span class="badge badge-' + H(t.status) + '">' + H(t.status) + '</span>';
120	}
121	
122	document.getElementById('ticket-form').addEventListener('submit', async (e) => {
123	  e.preventDefault();
124	  const btn = e.target.querySelector('button[type="submit"]');
125	  btn.classList.add('is-loading');
126	  try {
127	    const fd = new FormData(e.target);
128	    const body = {};
129	    fd.forEach((v,k) => { if(v) body[k] = k === 'estimated_weight_lbs' ? Number(v) : v; });
130	    const r = await api('/api/tickets', body);
131	    const el = document.getElementById('ticket-result');
132	    if (r.error) { showMsg(el, 'error', escapeHtml(r.error.message)); return; }
133	    const t = r.data;
134	    el.innerHTML = '<div class="msg msg-success">'
135	      + 'Ticket #' + H(t.id) + ' created — <span class="badge badge-' + H(t.status) + '">' + H(t.status) + '</span><br>'
136	      + '<strong>Estimated Payout: $' + H((t.estimated_payout || 0).toFixed(2)) + '</strong>'
137	      + (t.estimated_cap_applied ? ' <em>(cap applied)</em>' : '')
138	      + '</div>';
139	    refreshQueue();
140	    e.target.reset();
141	  } finally { btn.classList.remove('is-loading'); }
142	});
143	
144	// Queue inline actions
145	function cancelFromQueue(id) {
146	  const reason = window.prompt('Cancellation reason for ticket #' + id + ':');
147	  if (!reason) return;
148	  api('/api/tickets/' + id + '/cancel', {reason}).then(r => {
149	    if (r.error) showMsg(actionResult(), 'error', H(r.error.message));
150	    refreshQueue();
151	  });
152	}
153	function confirmVarianceFromQueue(id) {
154	  document.getElementById('action-ticket-id').value = id;
155	  showVarianceConfirm();
156	}
157	function dialFromQueue(id) {
158	  if (!confirmAction('Dial customer for ticket #' + id + '? This action is audited.')) return;
159	  api('/api/tickets/' + id + '/dial', {}).then(r => {
160	    if (r.error) { showMsg(actionResult(), 'error', H(r.error.message)); return; }
161	    const phone = r.data.phone;
162	    showMsg(actionResult(), 'success',
163	      'Dialing: <a href="tel:' + H(phone) + '" class="btn btn-success btn-sm" style="text-decoration:none">Call ' + H(r.data.last4 ? '••••' + r.data.last4 : phone) + '</a> (audit logged)');
164	  });
165	}
166	
167	function showVarianceConfirm() { show('variance-form'); show('variance-approval'); }
168	function showRefundForm() { show('refund-form'); }
169	function showCancelForm() { show('cancel-form'); }
170	
171	async function confirmVariance() {
172	  if (!requireTicketId()) return;
173	  const note = document.getElementById('variance-note').value.trim();
174	  if (!note) { showMsg(actionResult(), 'error', 'Confirmation note is required.'); return; }
175	  const r = await api('/api/tickets/' + tid() + '/confirm-variance', {confirmation_note: note});
176	  showApiResult(actionResult(), r, d => 'Variance confirmed — approval request #' + d.id);
177	  if (r.data) document.getElementById('var-req-id').value = r.data.id;
178	  refreshQueue();
179	}
180	
181	async function approveVariance() {
182	  const rid = document.getElementById('var-req-id').value;
183	  if (!rid) { showMsg(actionResult(), 'error', 'Enter an approval request ID.'); return; }
184	  const password = window.prompt('Re-enter your password to approve this variance:');
185	  if (!password) return;
186	  const r = await api('/api/tickets/variance/' + rid + '/approve', {password});
187	  showApiResult(actionResult(), r, ticketSummary);
188	  refreshQueue();
189	}
190	
191	async function rejectVariance() {
192	  const rid = document.getElementById('var-req-id').value;
193	  if (!rid) { showMsg(actionResult(), 'error', 'Enter an approval request ID.'); return; }
194	  const reason = document.getElementById('var-reject-reason').value.trim();
195	  if (!reason) { showMsg(actionResult(), 'error', 'Rejection reason is required.'); return; }
196	  if (!confirmAction('Reject this variance approval? This cannot be undone.')) return;
197	  const r = await api('/api/tickets/variance/' + rid + '/reject', {reason});
198	  showApiResult(actionResult(), r, d => 'Variance rejected — request #' + d.id);
199	  refreshQueue();
200	}
201	
202	async function initiateRefund() {
203	  if (!requireTicketId()) return;
204	  const body = {};
205	  const amt = document.getElementById('refund-amount').value;
206	  if (amt) {
207	    const reason = document.getElementById('refund-reason').value.trim();
208	    if (!reason) { showMsg(actionResult(), 'error', 'Reason required for partial refund.'); return; }
209	    body.refund_amount = parseFloat(amt);
210	    body.reason = reason;
211	  }
212	  if (!confirmAction('Submit a refund request for ticket #' + tid() + '?')) return;
213	  const r = await api('/api/tickets/' + tid() + '/refund', body);
214	  showApiResult(actionResult(), r, ticketSummary);
215	  refreshQueue();
216	}
217	
218	async function approveRefund() {
219	  const id = document.getElementById('refund-approve-id').value;
220	  if (!id) { showMsg(actionResult(), 'error', 'Enter a ticket ID.'); return; }
221	  const password = window.prompt('Re-enter your password to approve refund for ticket #' + id + ':');
222	  if (!password) return;
223	  const r = await api('/api/tickets/' + id + '/refund/approve', {password});
224	  showApiResult(actionResult(), r, ticketSummary);
225	  refreshQueue();
226	}
227	
228	async function rejectRefund() {
229	  const id = document.getElementById('refund-approve-id').value;
230	  if (!id) { showMsg(actionResult(), 'error', 'Enter a ticket ID.'); return; }
231	  const reason = document.getElementById('refund-reject-reason').value.trim();
232	  if (!reason) { showMsg(actionResult(), 'error', 'Rejection reason is required.'); return; }
233	  if (!confirmAction('Reject refund for ticket #' + id + '?')) return;
234	  const r = await api('/api/tickets/' + id + '/refund/reject', {reason});
235	  showApiResult(actionResult(), r, ticketSummary);
236	  refreshQueue();
237	}
