        )
    except PermissionError as e:
        return _html_error(str(e))
    except ValueError as e:
        return _html_error(str(e))
    phone = result["phone"]
    last4 = result.get("last4", "")
    label = f"••••{escape(last4)}" if last4 else "number"
    # Auto-trigger the OS dialer immediately, then show confirmation.
    return (
