122	document.getElementById('ticket-form').addEventListener('submit', async (e) => {
123	  e.preventDefault();
124	  const btn = e.target.querySelector('button[type="submit"]');
125	  btn.classList.add('is-loading');
126	  try {
127	    const fd = new FormData(e.target);
128	    const body = {};
129	    fd.forEach((v,k) => { if(v) body[k] = k === 'estimated_weight_lbs' ? Number(v) : v; });
130	    const r = await api('/api/tickets', body);
131	    const el = document.getElementById('ticket-result');
132	    if (r.error) { showMsg(el, 'error', escapeHtml(r.error.message)); return; }
133	    const t = r.data;
134	    el.innerHTML = '<div class="msg msg-success">'
135	      + 'Ticket #' + H(t.id) + ' created — <span class="badge badge-' + H(t.status) + '">' + H(t.status) + '</span><br>'
136	      + '<strong>Estimated Payout: $' + H((t.estimated_payout || 0).toFixed(2)) + '</strong>'
137	      + (t.estimated_cap_applied ? ' <em>(cap applied)</em>' : '')
138	      + '</div>';
139	    refreshQueue();
140	    e.target.reset();
141	  } finally { btn.classList.remove('is-loading'); }
142	});
